package commands

import (
	"context"
	"errors"
)

type EnrollCourseUsecaseParams struct {
	ctx           context.Context
	userId        string
	courseId      string
	sectionNumber *int
	topicNumber   *int
}

type EnrollCourseUsecase struct {
	courseRepository   CourseRepository
	progressRepository ProgressRepository
}

func NewEnrollCourseUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) EnrollCourseUsecase {
	return EnrollCourseUsecase{
		courseRepository:   courseRepo,
		progressRepository: progressRepo,
	}
}

type CourseRepository interface {
	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
}

type ProgressRepository interface {
	getProgress(ctx context.Context, userId string, courseId string) (Progress, error)
	save(ctx context.Context, progress *Progress) error
}

type EnrollCourseUsecaseInterface interface {
	execute(params EnrollCourseUsecaseParams) (string, error)
}

var ErrTopicNumberRequireSectionNumber = errors.New("topic number require section number")

func (usecase EnrollCourseUsecase) execute(params EnrollCourseUsecaseParams) (string, error) {
	course, err := usecase.courseRepository.getCourseByCourseId(params.ctx, params.courseId)
	if err != nil {
		return "", err
	}

	progress, err := usecase.progressRepository.getProgress(params.ctx, params.userId, params.courseId)
	if err != nil {
		return "", err
	}

	topicId, err := course.enroll(EnrollParams{
		UserId:        params.userId,
		SectionNumber: params.sectionNumber,
		TopicNumber:   params.topicNumber,
	}, &progress)
	if err != nil {
		return "", err
	}

	return topicId, usecase.progressRepository.save(params.ctx, &progress)
}

package commands

import (
	"encoding/json"
	"log"
	"net/http"
	"regexp"

	"github.com/harusame0616/ijuku/apps/api/lib/validation"
)

var uuidRegex = regexp.MustCompile(`^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$`)

type Handler struct {
	usecase EnrollCourseUsecaseInterface
}

func NewHandler(usecase EnrollCourseUsecaseInterface) *Handler {
	return &Handler{usecase: usecase}
}

func (h *Handler) PostEnrollmentHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	courseId := r.PathValue("courseId")

	if courseId == "" {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "courseId must be required"})
		return
	}

	if !uuidRegex.MatchString(courseId) {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "courseId must be UUID format"})
		return
	}

	// TODO: 本来は API キーから userId を解決するべきだが、認証機能未実装のため暫定的に body から取得している
	var enrollmentBodyParams struct {
		UserId        string `json:"userId"`
		SectionNumber *int   `json:"sectionNumber"`
		TopicNumber   *int   `json:"topicNumber"`
	}

	defer r.Body.Close()
	if err := json.NewDecoder(r.Body).Decode(&enrollmentBodyParams); err != nil {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "body parameter is invalid json format"})
		return
	}

	if enrollmentBodyParams.UserId == "" {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "userId must be required"})
		return
	}

	if !uuidRegex.MatchString(enrollmentBodyParams.UserId) {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "userId must be UUID format"})
		return
	}

	topicId, err := h.usecase.execute(EnrollCourseUsecaseParams{
		ctx:           r.Context(),
		userId:        enrollmentBodyParams.UserId,
		courseId:      courseId,
		sectionNumber: enrollmentBodyParams.SectionNumber,
		topicNumber:   enrollmentBodyParams.TopicNumber,
	})

	if err == ErrTopicNumberRequireSectionNumber {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "topic number require section number"})
		return
	}

	if err == ErrEnrollmentNumberIsNotFound {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "enrollment number is not found"})
		return
	}

	if err == ErrEnrollmentNotAllowed {
		w.WriteHeader(http.StatusForbidden)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": "FORBIDDEN", "message": "enrollment not allowed"})
		return
	}

	if err != nil {
		log.Printf("PostEnrollmentHandler error: %v", err)
		w.WriteHeader(http.StatusInternalServerError)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": "INTERNAL_SERVER_ERROR", "message": "internal server error"})
		return
	}

	w.WriteHeader(http.StatusCreated)
	_ = json.NewEncoder(w).Encode(map[string]string{"topicId": topicId})
}

package commands

import (
	"context"
	"encoding/json"
	"time"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcCourseRepository struct {
	sqrc db.Querier
}

func NewSqrcCourseRepository(q db.Querier) *SqrcCourseRepository {
	return &SqrcCourseRepository{sqrc: q}
}

func (repository *SqrcCourseRepository) getCourseByCourseId(ctx context.Context, courseId string) (Course, error) {
	var courseIdUuid pgtype.UUID

	if err := courseIdUuid.Scan(courseId); err != nil {
		return Course{}, err
	}

	courseRaw, err := repository.sqrc.GetCourseById(ctx, courseIdUuid)
	if err != nil {
		return Course{}, err
	}

	return toCourse(courseRaw), nil
}

func toCourse(raw db.GetCourseByIdRow) Course {
	var tags []string
	json.Unmarshal(raw.Tags, &tags)

	type topicRaw struct {
		CourseSectionTopicId string `json:"course_section_topic_id"`
		Title                string `json:"title"`
		Description          string `json:"description"`
		Prerequisites        string `json:"prerequisites"`
		Knowledge            string `json:"knowledge"`
		Flow                 string `json:"flow"`
		Quiz                 string `json:"quiz"`
		CompletionCriteria   string `json:"completion_criteria"`
	}
	type sectionRaw struct {
		CourseSectionId string     `json:"course_section_id"`
		Title           string     `json:"title"`
		Description     string     `json:"description"`
		Topics          []topicRaw `json:"topics"`
	}

	var sectionsRaw []sectionRaw
	json.Unmarshal(raw.Sections, &sectionsRaw)

	sections := make([]Section, len(sectionsRaw))
	for i, s := range sectionsRaw {
		topics := make([]Topic, len(s.Topics))
		for j, t := range s.Topics {
			topics[j] = Topic{
				topicId:            t.CourseSectionTopicId,
				title:              t.Title,
				description:        t.Description,
				prerequisites:      t.Prerequisites,
				knowledge:          t.Knowledge,
				flow:               t.Flow,
				quiz:               t.Quiz,
				completionCriteria: t.CompletionCriteria,
				number:             j,
			}
		}
		sections[i] = Section{
			sectionId:   s.CourseSectionId,
			title:       s.Title,
			description: s.Description,
			number:      i,
			topics:      topics,
		}
	}

	var publishedAt *string
	if raw.PublishedAt.Valid {
		t := raw.PublishedAt.Time.Format(time.RFC3339)
		publishedAt = &t
	}

	return Course{
		courseId:      raw.CourseID.String(),
		title:         raw.Title,
		description:   raw.Description,
		slug:          raw.Slug,
		tags:          tags,
		publishStatus: raw.PublishStatus,
		category: Category{
			categoryId: raw.CategoryID.String(),
			name:       raw.CategoryName,
		},
		publishedAt: publishedAt,
		author: Author{
			authorId: raw.AuthorID.String(),
			name:     raw.AuthorName,
		},
		visibility: raw.Visibility,
		sections:   sections,
	}
}

