			t.Errorf("ステータスコードが400であること: got %d", w.Result().StatusCode)
		}
		body := decodeBody(t, w)
		if body["code"] != "INPUT_VALIDATION_ERROR" {
			t.Errorf("codeが一致すること: got %q", body["code"])
		}
	})

	t.Run("リクエストボディが不正なJSONの場合400を返す", func(t *testing.T) {
		h := NewHandler(&mockUsecase{})
