		w := httptest.NewRecorder()

		h.PostEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusBadRequest {
			t.Errorf("ステータスコードが400であること: got %d", w.Result().StatusCode)
		}
		body := decodeBody(t, w)
