   128→type progressRecord struct {
   129→	topicID string
   130→	status  string
   131→}
   132→
   133→func getProgresses(t *testing.T, ctx context.Context, pool *pgxpool.Pool) []progressRecord {
   134→	t.Helper()
   135→	rows, err := pool.Query(ctx,
   136→		`SELECT course_section_topic_id, status FROM user_topic_progresses WHERE user_id = $1 ORDER BY course_section_topic_id`,
   137→		enrollTestUserID,
   138→	)
   139→	if err != nil {
   140→		t.Fatalf("progressの取得に失敗しました: %v", err)
   141→	}
   142→	defer rows.Close()
   143→
   144→	var records []progressRecord
   145→	for rows.Next() {
   146→		var r progressRecord
   147→		if err := rows.Scan(&r.topicID, &r.status); err != nil {
   148→			t.Fatalf("progressのスキャンに失敗しました: %v", err)
   149→		}
   150→		records = append(records, r)
   151→	}
   152→	return records
   153→}
